"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["65583"],{87527(t){t.exports=JSON.parse('{"tag":{"label":"patterns","permalink":"/sysanalyst-kb.github.io/docs/tags/patterns","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":7,"items":[{"id":"architecture/cqrs","title":"CQRS \u2014 Command Query Responsibility Segregation","description":"CQRS \u2014 \u043F\u0430\u0442\u0442\u0435\u0440\u043D, \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0439 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u0447\u0442\u0435\u043D\u0438\u044F (Query) \u0438 \u0437\u0430\u043F\u0438\u0441\u0438 (Command). \u0412 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0435 \u043E\u0434\u043D\u0430 \u043C\u043E\u0434\u0435\u043B\u044C \u0434\u0430\u043D\u043D\u044B\u0445 \u0438 \u0434\u043B\u044F \u0447\u0442\u0435\u043D\u0438\u044F, \u0438 \u0434\u043B\u044F \u0437\u0430\u043F\u0438\u0441\u0438. CQRS \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u0440\u0430\u0437\u043D\u044B\u0435 \u043C\u043E\u0434\u0435\u043B\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/cqrs"},{"id":"architecture/eda-detailed","title":"Event-Driven Architecture (\u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E)","description":"\u0412\u044B \u0443\u0436\u0435 \u0437\u043D\u0430\u0435\u0442\u0435 \u043E\u0441\u043D\u043E\u0432\u044B EDA \u0438\u0437 \u0440\u0430\u0437\u0434\u0435\u043B\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438. \u0422\u0435\u043F\u0435\u0440\u044C \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0438\u043C \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0435 \u0430\u0441\u043F\u0435\u043A\u0442\u044B: \u043A\u0430\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u043A\u0430\u043A \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u043F\u043E\u0442\u043E\u043A\u0438 \u0438 \u043A\u0430\u043A EDA \u043C\u0435\u043D\u044F\u0435\u0442 \u0434\u0438\u0437\u0430\u0439\u043D \u0441\u0438\u0441\u0442\u0435\u043C\u044B.","permalink":"/sysanalyst-kb.github.io/docs/architecture/eda-detailed"},{"id":"architecture/microservices-patterns","title":"\u041C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u0431\u0430\u0437\u043E\u0432\u044B\u0435 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B","description":"\u041F\u0435\u0440\u0435\u0445\u043E\u0434 \u043D\u0430 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u044D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u044E, \u0430 \u043F\u0440\u043E \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044E. \u041A\u0430\u0436\u0434\u044B\u0439 \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u044B \u0440\u0435\u0448\u0430\u0435\u0442 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u0443\u044E \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0443, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u043F\u0440\u0438 \u0434\u0435\u043B\u0435\u043D\u0438\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043D\u0430 \u0447\u0430\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/microservices-patterns"},{"id":"architecture/monolith-vs-microservices","title":"\u041C\u043E\u043D\u043E\u043B\u0438\u0442 vs \u041C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B","description":"\u0421\u043F\u043E\u0440 \xab\u043C\u043E\u043D\u043E\u043B\u0438\u0442 \u0438\u043B\u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B\xbb \u0434\u0430\u0432\u043D\u043E \u043F\u043E\u0442\u0435\u0440\u044F\u043B \u0441\u043C\u044B\u0441\u043B. \u042D\u0442\u043E \u043D\u0435 \u0432\u043E\u043F\u0440\u043E\u0441 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0438, \u0430 \u0432\u043E\u043F\u0440\u043E\u0441 \u043A\u043E\u043C\u043F\u0440\u043E\u043C\u0438\u0441\u0441\u0430. \u041E\u0431\u0430 \u043F\u043E\u0434\u0445\u043E\u0434\u0430 \u0438\u043C\u0435\u044E\u0442 \u0446\u0435\u043D\u0443, \u0438 \u0432\u044B\u0431\u043E\u0440 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430: \u0441\u0442\u0430\u0434\u0438\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430, \u0440\u0430\u0437\u043C\u0435\u0440\u0430 \u043A\u043E\u043C\u0430\u043D\u0434\u044B, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0439 \u043A \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044E.","permalink":"/sysanalyst-kb.github.io/docs/architecture/monolith-vs-microservices"},{"id":"specialization/ai-agents-multi","title":"\u041C\u0443\u043B\u044C\u0442\u0438\u0430\u0433\u0435\u043D\u0442\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u2014 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B, \u043E\u0440\u043A\u0435\u0441\u0442\u0440\u0430\u0446\u0438\u044F, \u043A\u043E\u043C\u043C\u0443\u043D\u0438\u043A\u0430\u0446\u0438\u044F","description":"\u041C\u0443\u043B\u044C\u0442\u0438\u0430\u0433\u0435\u043D\u0442\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u2014 \u044D\u0442\u043E \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E AI-\u0430\u0433\u0435\u043D\u0442\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0442 \u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C \u0434\u043B\u044F \u0440\u0435\u0448\u0435\u043D\u0438\u044F \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u0437\u0430\u0434\u0430\u0447. \u041A\u0430\u0436\u0434\u044B\u0439 \u0430\u0433\u0435\u043D\u0442 \u0438\u043C\u0435\u0435\u0442 \u0441\u0432\u043E\u044E \u0440\u043E\u043B\u044C \u0438 \u043D\u0430\u0431\u043E\u0440 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u0430 \u043E\u0440\u043A\u0435\u0441\u0442\u0440\u0430\u0442\u043E\u0440 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u0438\u0445 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0443 \u0432\u0430\u0436\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B \u043C\u0443\u043B\u044C\u0442\u0438\u0430\u0433\u0435\u043D\u0442\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C, \u0447\u0442\u043E\u0431\u044B \u0432\u044B\u0431\u0438\u0440\u0430\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u0443\u044E \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443 \u0438 \u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u043A\u043E\u043C\u043C\u0443\u043D\u0438\u043A\u0430\u0446\u0438\u0438 \u0438 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ai-agents-multi"},{"id":"architecture/layered-architecture","title":"\u0421\u043B\u043E\u0438\u0441\u0442\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 (layered)","description":"\u0421\u043B\u043E\u0438\u0441\u0442\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u2014 \u0441\u0430\u043C\u044B\u0439 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0451\u043D\u043D\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u043A\u043E\u0434\u0430. \u0418\u0434\u0435\u044F \u043F\u0440\u043E\u0441\u0442\u0430: \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 \u0433\u043E\u0440\u0438\u0437\u043E\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0443\u0440\u043E\u0432\u043D\u0438, \u043A\u0430\u0436\u0434\u044B\u0439 \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0441\u0432\u043E\u044E \u0437\u043E\u043D\u0443 \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438. \u0412\u0435\u0440\u0445\u043D\u0438\u0439 \u0441\u043B\u043E\u0439 \u043C\u043E\u0436\u0435\u0442 \u043E\u0431\u0440\u0430\u0449\u0430\u0442\u044C\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043A \u0441\u043E\u0441\u0435\u0434\u043D\u0435\u043C\u0443 \u043D\u0438\u0436\u043D\u0435\u043C\u0443 \u2014 \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0441\u0442\u0440\u043E\u0433\u043E\u0439 \u0438\u0435\u0440\u0430\u0440\u0445\u0438\u0435\u0439.","permalink":"/sysanalyst-kb.github.io/docs/architecture/layered-architecture"},{"id":"architecture/what-is-architecture","title":"\u0427\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u041F\u041E","description":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u2014 \u044D\u0442\u043E \u0440\u0435\u0448\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u043B\u043E\u0436\u043D\u043E \u0438\u0437\u043C\u0435\u043D\u0438\u0442\u044C \u043F\u043E\u0441\u043B\u0435 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043E\u043D\u0438 \u043F\u0440\u0438\u043D\u044F\u0442\u044B. \u0415\u0441\u043B\u0438 \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u0435 \u0438\u043C\u044F \u0444\u0443\u043D\u043A\u0446\u0438\u0438 \u043C\u043E\u0436\u043D\u043E \u0438\u0441\u043F\u0440\u0430\u0432\u0438\u0442\u044C \u0437\u0430 \u043C\u0438\u043D\u0443\u0442\u0443, \u0442\u043E \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u0439 \u0432\u044B\u0431\u043E\u0440 \u043C\u0435\u0436\u0434\u0443 \u043C\u043E\u043D\u043E\u043B\u0438\u0442\u043E\u043C \u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043C\u0438 \u0431\u0443\u0434\u0435\u0442 \u0430\u0443\u043A\u0430\u0442\u044C\u0441\u044F \u0433\u043E\u0434\u0430\u043C\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/what-is-architecture"}],"unlisted":false}}')}}]);